package main

import (
	"sync"
	"fmt"
)

type Account struct {
	balance int
	mutex   sync.Mutex
}

type Bank struct {
	accounts map[string]*Account
	mutex    sync.Mutex
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]*Account),
	}
}

func (b *Bank) Deposit(accountID string, amount int) {
	b.mutex.Lock()
	account, ok := b.accounts[accountID]
	if !ok {
		account = &Account{}
		b.accounts[accountID] = account
	}
	b.mutex.Unlock()

	account.mutex.Lock()
	account.balance += amount
	account.mutex.Unlock()
}

func (b *Bank) Withdraw(accountID string, amount int) bool {
	b.mutex.Lock()
	account, ok := b.accounts[accountID]
	b.mutex.Unlock()

	if !ok {
		return false
	}

	account.mutex.Lock()
	defer account.mutex.Unlock()

	if account.balance < amount {
		return false
	}

	account.balance -= amount
	return true
}

func (b *Bank) Balance(accountID string) (int, bool) {
	b.mutex.Lock()
	account, ok := b.accounts[accountID]
	b.mutex.Unlock()

	if !ok {
		return 0, false
	}

	account.mutex.Lock()
	defer account.mutex.Unlock()

	return account.balance, true
}

func main() {
	bank := NewBank()

	go bank.Deposit("123", 100)
	go bank.Withdraw("123", 50)
	go bank.Deposit("123", 200)

	balance, _ := bank.Balance("123")
	fmt.Println(balance)
}